+                .saturating_sub(previous.budget_exhaustions),
+            decision_points: current
+                .decision_points
+                .saturating_sub(previous.decision_points),
+        };
+        self.chaos_stats.merge(&delta);
+        self.seen_reactor_chaos_stats = current;
+    }
